/**
 * Signals in message VCU_SUSP_R.
 *
 * The measurements for rear suspension

 *
 * All signal values are as on the CAN bus.
 */
struct can_mcu_vcu_susp_r_t {
    /**
     * Suspension Potentiometers Rear Left
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint16_t susp_pot_rl;

    /**
     * Suspension Potentiometers Rear Right
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint16_t susp_pot_rr;
};

/**
 * Signals in message DASH_APPS.
 *
 * APPS Raw Values & SCS states, Brake Pressure & SCS states
 *
 * All signal values are as on the CAN bus.
 */
struct can_mcu_dash_apps_t {
    /**
     * Range: 0..1 (0..1 ADC)
     * Scale: 1
     * Offset: 0
     */
    uint16_t apps1_raw;

    /**
     * Range: 0..1 (0..1 ADC)
     * Scale: 1
     * Offset: 0
     */
    uint16_t apps2_raw;

    /**
     * checks if APPSs's signals are short circuited
     *
     * Range: 0..1 (0..1 Boolean)
     * Scale: 1
     * Offset: 0
     */
    uint8_t apps_sc_signals;

    /**
     * checks if any of the APPS signal is short circuited to supply
     *
     * Range: 0..1 (0..1 Boolean)
     * Scale: 1
     * Offset: 0
     */
    uint8_t apps_sc_sup;

    /**
     * checks if any of the APPS signal is short circuited to GND
     *
     * Range: 0..1 (0..1 Boolean)
     * Scale: 1
     * Offset: 0
     */
    uint8_t apps_sc_gnd;

    /**
     * checks if any of APPSs' signals is out of range
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t apps_out_of_range;
};

/**
 * Signals in message VCU_BOOLS.
 *
 * LEDs to Dashboard and bools from ECU to ASB and AUX
 *
 * All signal values are as on the CAN bus.
 */
struct can_mcu_vcu_bools_t {
    /**
     * Signal to trigger Buzzer
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t buzzer;

    /**
     * Enable ON (R2D sequence done)
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t enable;

    /**
     * SafeState_OK == 1 means no SafeState error present. Sent by Fusebox.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t safe_state_ok;

    /**
     * AMS Error Latched on Fusebox. If there is no AMS Error, Reset button must be pressed to delatch
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t ams_error_latched;

    /**
     * IMD Error Latched on Fusebox. If there is no IMD Error, Reset button must be pressed to delatch
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t imd_error_latched;

    /**
     * Mode == 1: Manual. Mode == 0: Driverless.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t mode;

    /**
     * AUX_AIR_Plus == 1 -> AIR+ is open.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t aux_air_plus;
};

/**
 * Signals in message DASH_STEERING.
 *
 * Steering Sensor
 *
 * All signal values are as on the CAN bus.
 */
struct can_mcu_dash_steering_t {
    /**
     * Steering Angle Sensor value in rad
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    float steering;

    /**
     * Steering sensor measured voltage
     *
     * Range: -
     * Scale: 0.001
     * Offset: 0
     */
    int16_t steering_voltage;
};

/**
 * Signals in message DASH_BOOLS.
 *
 * Dashboard buttons and toggle switches
 *
 * All signal values are as on the CAN bus.
 */
struct can_mcu_dash_bools_t {
    /**
     * Start Button on Dashboard. Start == 1 if button pressed.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t start;

    /**
     * AddAct Button signal, either from dashboard or external button, depending on vehicle Mode. AddAct == 1 if correct button pressed.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t add_act;

    /**
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t steering_implausibility;

    /**
     * Monitor place
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t monitor;

    /**
     * Cooling enable
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t cooling_status;

    /**
     * TS_Off analog signal received from Fusebox
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t ts_off;

    /**
     * Range: 0..15 (0..15 Boolean)
     * Scale: 1
     * Offset: 0
     */
    uint8_t rotary_active_mode;

    /**
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t setup;

    /**
     * Which place is chosen
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t main_menu;

    /**
     * The current place at the secont column of the menu
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t sub_menu;

    /**
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t screen;

    /**
     * External Reset button for SDC. Reset_SDC == 1 if button pressed.
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t reset_sdc;

    /**
     * == 1 if SDC 24V present before ASB
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t sd_before_asb_ok;

    /**
     * == 1 if SDC 24V present after BSPD
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t sd_after_bspd_ok;

    /**
     * == 1 if SDC 24V present before Inertia switch
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t sd_before_inertia_ok;

    /**
     * == 1 if SDC 24V present before TSMS
     *
     * Range: -
     * Scale: 1
     * Offset: 0
     */
    uint8_t sd_before_tsms_ok;
};

